mapper.select:
select * from sys_purchase_check
and purchase_no like concat('%',#{purchaseNo},'%') and supplier_name like concat('%',#{supplierName},'%') and check_result = #{checkResult}
order by create_time desc

mapper.update:
update sys_purchase_check
check_result = #{checkResult}, check_remark = #{checkRemark}, check_by = #{checkBy}, check_time = #{checkTime}, update_by = #{updateBy}, update_time = #{updateTime}
where check_id = #{checkId}
